checker_dsl:
EXISTS (`Field F`, `Class C`) {
  AND {
    (`class C has an annotation whose type name is "ThreadSafe"`),
    (`field F is declared in class C`),
    NOT {
      OR {
        (`field F is final`),
        (`field F is static`),
        (`field F is volatile`),
        EXISTS (`Type T1`) {
          AND {
            (`T1 is the declared type of field F`),
            OR {
              EXISTS (`RefType RT1`) {
                AND {
                  (`T1 is RT1`),
                  (`the source declaration of RT1 has a name matching the pattern "Atomic%" or "Concurrent%"`)
                }
              },
              EXISTS (`RefType RT2`) {
                AND {
                  (`T1 is RT2`),
                  (`the source declaration of RT2 has name "ThreadLocal"`)
                }
              },
              EXISTS (`RefType RT3`) {
                AND {
                  (`T1 is RT3`),
                  (`the package of RT3 has name "java.util.concurrent"`)
                }
              },
              (`T1 is ClassAnnotatedAsThreadSafe CTS1`)
            }
          }
        },
        EXISTS (`Expr INIT`, `Type T2`) {
          AND {
            (`INIT is the initializer expression of field F`),
            (`T2 is the type of expression INIT`),
            OR {
              EXISTS (`RefType RT4`) {
                AND {
                  (`T2 is RT4`),
                  (`the source declaration of RT4 has a name matching the pattern "Atomic%" or "Concurrent%"`)
                }
              },
              EXISTS (`RefType RT5`) {
                AND {
                  (`T2 is RT5`),
                  (`the source declaration of RT5 has name "ThreadLocal"`)
                }
              },
              EXISTS (`RefType RT6`) {
                AND {
                  (`T2 is RT6`),
                  (`the package of RT6 has name "java.util.concurrent"`)
                }
              },
              (`T2 is ClassAnnotatedAsThreadSafe CTS2`)
            }
          }
        },
        FORALL (`Expr V`) {
          AND {
            (`V is a value assigned to field F`),
            OR {
              (`V is the initializer expression of field F`),
              EXISTS (`Callable CON`, `Type DEC`) {
                AND {
                  (`DEC is the declaring type of field F`),
                  (`CON is a constructor of DEC`),
                  (`CON is the enclosing callable of expression V`)
                }
              }
            },
            OR {
              AND {
                (`the type of field F has name "byte"`),
                EXISTS (`IntegerLiteral IL1`) {
                  AND {
                    (`V is IL1`),
                    (`the int value of IL1 is 0`)
                  }
                }
              },
              AND {
                (`the type of field F has name "short"`),
                EXISTS (`IntegerLiteral IL2`) {
                  AND {
                    (`V is IL2`),
                    (`the int value of IL2 is 0`)
                  }
                }
              },
              AND {
                (`the type of field F has name "int"`),
                EXISTS (`IntegerLiteral IL3`) {
                  AND {
                    (`V is IL3`),
                    (`the int value of IL3 is 0`)
                  }
                }
              },
              AND {
                (`the type of field F has name "long"`),
                OR {
                  EXISTS (`LongLiteral LL`) {
                    AND {
                      (`V is LL`),
                      (`the value of LL is "0"`)
                    }
                  },
                  EXISTS (`IntegerLiteral IL4`) {
                    AND {
                      (`V is IL4`),
                      (`the value of IL4 is "0"`)
                    }
                  }
                }
              },
              AND {
                (`the type of field F has name "float"`),
                EXISTS (`FloatLiteral FL`) {
                  AND {
                    (`V is FL`),
                    (`the value of FL is "0.0"`)
                  }
                }
              },
              AND {
                (`the type of field F has name "double"`),
                EXISTS (`DoubleLiteral DL`) {
                  AND {
                    (`V is DL`),
                    (`the value of DL is "0.0"`)
                  }
                }
              },
              AND {
                (`the type of field F has name "char"`),
                EXISTS (`CharacterLiteral CL`) {
                  AND {
                    (`V is CL`),
                    (`the code point value of CL is 0`)
                  }
                }
              },
              AND {
                (`the type of field F has name "boolean"`),
                EXISTS (`BooleanLiteral BL`) {
                  AND {
                    (`V is BL`),
                    (`the boolean value of BL is false`)
                  }
                }
              },
              AND {
                NOT {
                  (`the type name of field F is in the list ["byte", "short", "int", "long", "float", "double", "char", "boolean"]`)
                },
                EXISTS (`NullLiteral NL`) {
                  (`V is NL`)
                }
              }
            }
          }
        }
      }
    }
  }
}
